      {
        "title": "Second leg",
        "body": "He arrives with 7 gallons, so he used 5 gallons on the second leg.",
        "equation": "5 × 35 = 175"
      },
      {
        "title": "Total distance",
        "body": "The total distance is 350 + 175 = 525 miles."
      }
