      { "title": "Solve", "narration": "a₆ = A³B⁵. Since 4000 = 5³ × 2⁵, A = 5 and B = 2.", "visualHint": "Factoring and matching." },
      { "title": "Check", "narration": "5, 2, 10, 20, 200, 4000. ✓ The answer is (D).", "visualHint": "Sequence verified." }
