      { "title": "Solve", "narration": "Corner: 4×5=20. Edge: 4×3=12. Center: 0. Total: 32.", "visualHint": "Cases counted." },
      { "title": "Check", "narration": "32 ways. The answer is (E).", "visualHint": "Answer E circled." }
