    "year": 2026,
    "problemNumber": 16,
    "category": "Number Theory",
    "subcategory": "Divisibility",
    "difficulty": 4,
    "statement": "Consider all positive four-digit integers consisting of only even digits. What fraction of these integers are divisible by 4?",
